public class HackathonWinner {

    private static int getScore(String s) {
        int score = 0;

        for (char c : s.toCharArray()) {
            if (c == 'E') score += 1;
            else if (c == 'M') score += 3;
            else if (c == 'H') score += 5;
        }

        return score;
    }

    public static String hackathonWinner(String erica, String bob) {
        int ericaScore = getScore(erica);
        int bobScore = getScore(bob);

        if (ericaScore > bobScore) return "Erica";
        if (bobScore > ericaScore) return "Bob";
        return "Tie";
    }
}

