def hackathon_winner(erica: str, bob: str) -> str:
    points = {'E': 1, 'M': 3, 'H': 5}

    erica_score = sum(points[ch] for ch in erica)
    bob_score = sum(points[ch] for ch in bob)

    if erica_score > bob_score:
        return "Erica"
    elif bob_score > erica_score:
        return "Bob"
    else:
        return "Tie"
